import "server-only";

import { redirect } from "next/navigation";

import { auth } from "@/auth";
import { prisma } from "@/lib/prisma";

export async function getOwnerSession() {
  const session = await auth();

  if (!session?.user?.id) {
    return null;
  }

  const owner = await prisma.user.findUnique({
    where: {
      id: session.user.id
    },
    select: {
      id: true,
      username: true
    }
  });

  if (!owner) {
    return null;
  }

  return {
    id: owner.id,
    name: owner.username
  };
}

export async function requireOwnerSession() {
  const session = await getOwnerSession();

  if (!session) {
    redirect("/login");
  }

  return session;
}

import type { NextAuthConfig } from "next-auth";

export const authConfig = {
  providers: [],
  trustHost: true,
  pages: {
    signIn: "/login"
  },
  session: {
    strategy: "jwt"
  },
  callbacks: {
    authorized({ auth, request: { nextUrl } }) {
      if (nextUrl.pathname.startsWith("/app")) {
        return Boolean(auth?.user);
      }

      return true;
    }
  }
} satisfies NextAuthConfig;

import "next-auth";

declare module "next-auth" {
  interface Session {
    user: {
      id: string;
      name?: string | null;
      email?: string | null;
      image?: string | null;
    };
  }

  interface User {
    id: string;
  }
}

import "dotenv/config";

import { PrismaBetterSqlite3 } from "@prisma/adapter-better-sqlite3";
import { PrismaClient } from "@prisma/client";

import { createPasswordHash, verifyPassword } from "../src/lib/auth/password";

const databaseUrl = process.env.DATABASE_URL;

if (!databaseUrl) {
  throw new Error("DATABASE_URL must be set before seeding.");
}

const prisma = new PrismaClient({
  adapter: new PrismaBetterSqlite3({
    url: databaseUrl
  })
});

async function main() {
  const username = process.env.OWNER_USERNAME;
  const password = process.env.OWNER_PASSWORD;

  if (!username || !password) {
    throw new Error("OWNER_USERNAME and OWNER_PASSWORD must be set before seeding the owner account.");
  }

  const existing = await prisma.user.findUnique({
    where: {
      username
    }
  });

  if (!existing) {
    await prisma.user.create({
      data: {
        username,
        passwordHash: createPasswordHash(password)
      }
    });
    return;
  }

  if (verifyPassword(password, existing.passwordHash)) {
    return;
  }

  await prisma.user.update({
    where: {
      username
    },
    data: {
      passwordHash: createPasswordHash(password)
    }
  });
}

main()
  .catch((error) => {
    console.error(error);
    process.exitCode = 1;
  })
  .finally(async () => {
    await prisma.$disconnect();
  });

import { Button, FormField, IntroBlock, SectionHeading, Surface } from "@/components/ui/primitives";
import { loginAction } from "./actions";

type LoginPageProps = {
  searchParams?: Promise<{
    error?: string;
  }>;
};

export default async function LoginPage({ searchParams }: LoginPageProps) {
  const resolvedSearchParams = (await searchParams) ?? {};
  const hasError = resolvedSearchParams.error === "CredentialsSignin";

  return (
    <div className="feature-layout login-layout">
      <Surface className="login-intro-card" density="compact" tone="hero">
        <IntroBlock
          compact
          description="Owner-only access to notes, links, tags, and search."
          eyebrow="Owner access"
          title="Sign in to the private vault."
        />
      </Surface>

      <Surface className="login-form-card" density="compact" tone="panel">
        <SectionHeading meta="Owner-only" title="Credentials" />
        <form action={loginAction} className="sign-in-form ui-form-stack">
          <FormField label="Username">
            <input autoComplete="username" name="username" placeholder="owner" required type="text" />
          </FormField>
          <FormField label="Password">
            <input autoComplete="current-password" name="password" required type="password" />
          </FormField>
          <div className="button-row">
            <Button type="submit">Sign in</Button>
          </div>
        </form>
        {hasError ? <p className="signin-error">Credentials were rejected. Try the owner username and password again.</p> : null}
      </Surface>
    </div>
  );
}

